module branch_predictor(  
    input clk,  
    input reset,  
    input taken,  
    output reg prediction  
);  
    reg [1:0] unused_counter;  

    always @(posedge clk or posedge reset) begin  
        if (reset)  
            unused_counter <= 2'b00;  
        else begin  
            if (taken)  
                unused_counter <= (unused_counter == 2'b11) ? 2'b11 : unused_counter + 1;  
            else  
                unused_counter <= (unused_counter == 2'b00) ? 2'b00 : unused_counter - 1;  
        end  
    end  

    always @(*) begin  
        prediction = (unused_counter[1] == 1'b1);  
    end  
endmodule
